package com.kalyani.car_rental_backend.coupon.entity;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;
@Entity @Table(name="coupons",uniqueConstraints=@UniqueConstraint(name="uk_coupon_code",columnNames="code"))public class Coupon{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(nullable=false)private String code;@Column(nullable=false)private String discountType;@Column(nullable=false)private BigDecimal discountValue;private BigDecimal minimumAmount;private BigDecimal maximumDiscount;private LocalDateTime validFrom;private LocalDateTime validUntil;@Column(nullable=false)private boolean active=true;private Integer usageLimit;private Integer usedCount=0;public Long getId(){return id;}public String getCode(){return code;}public void setCode(String v){code=v;}public String getDiscountType(){return discountType;}public void setDiscountType(String v){discountType=v;}public BigDecimal getDiscountValue(){return discountValue;}public void setDiscountValue(BigDecimal v){discountValue=v;}public BigDecimal getMinimumAmount(){return minimumAmount;}public void setMinimumAmount(BigDecimal v){minimumAmount=v;}public BigDecimal getMaximumDiscount(){return maximumDiscount;}public void setMaximumDiscount(BigDecimal v){maximumDiscount=v;}public LocalDateTime getValidFrom(){return validFrom;}public void setValidFrom(LocalDateTime v){validFrom=v;}public LocalDateTime getValidUntil(){return validUntil;}public void setValidUntil(LocalDateTime v){validUntil=v;}public boolean isActive(){return active;}public void setActive(boolean v){active=v;}public Integer getUsageLimit(){return usageLimit;}public void setUsageLimit(Integer v){usageLimit=v;}public Integer getUsedCount(){return usedCount;}public void setUsedCount(Integer v){usedCount=v;}}
